private void AddPropertyMaps(List<Expression> actions)
    {
        var propertyMaps = _typeMap.OrderedPropertyMaps();
        if (propertyMaps == null)
        {
            return;
        }

        foreach (var propertyMap in propertyMaps)
        {
            if (!propertyMap.CanResolveValue)
            {
                continue;
            }

            try
            {
                var property = TryMemberMap(propertyMap,
                    CreatePropertyMapFunc(propertyMap, _destination, propertyMap.DestinationMember));
                if (_typeMap.ConstructorParameterMatches(propertyMap.DestinationName))
                {
                    property = _initialDestination.IfNullElse(_configuration.Default(property.Type), property);
                }

                actions.Add(property);
            }
            catch (Exception e) when (e is not AutoMapperConfigurationException)
            {
                throw new AutoMapperMappingException("Error building member mapping strategy.", e, propertyMap);
            }
        }
    }

public string? Singularize(string? word, bool inputIsKnownToBePlural = true, bool skipSimpleWords = false)
    {
        if (word == null)
        {
            return null;
        }
        var s = LetterS(word);
        if (s != null)
        {
            return s;
        }

        var result = ApplyRules(singulars, word, skipSimpleWords);

        if (inputIsKnownToBePlural)
        {
            return result ?? word;
        }

        // the Plurality is unknown so we should check all possibilities
        var asPlural = ApplyRules(plurals, word, false);
        if (asPlural == word ||
            word + "s" == asPlural)
        {
            return result ?? word;
        }

        var asPluralAsSingular = ApplyRules(singulars, asPlural, false);
        if (asPluralAsSingular != word ||
            result == word)
        {
            return result ?? word;
        }

        return word;
    }

Func<CultureInfo, TLocaliser> FindLocaliser(CultureInfo culture)
    {
        // Check if already frozen (fast path without lock)
        var frozen = frozenLocalisers;
        if (frozen == null)
        {
            lock (lockObject)
            {
                // Double-check after acquiring lock
                frozen = frozenLocalisers;
                if (frozen == null)
                {
                    // Freeze the dictionary on first use for better read performance
                    frozen = localisersBuilder.ToFrozenDictionary();
                    frozenLocalisers = frozen;
                }
            }
        }

        for (var c = culture; !string.IsNullOrEmpty(c.Name); c = c.Parent)
        {
            if (frozen.TryGetValue(c.Name, out var localiser))
            {
                return localiser;
            }
        }

        return defaultLocaliser;
    }

public static IEnumerable<TSource> PreScan<TSource>(
    this IEnumerable<TSource> source,
    Func<TSource, TSource, TSource> transformation,
    TSource identity)
{
    if (source == null) throw new ArgumentNullException(nameof(source));
    if (transformation == null) throw new ArgumentNullException(nameof(transformation));

    return _(source, transformation, identity);

    static IEnumerable<TSource> _(
        IEnumerable<TSource> source,
        Func<TSource, TSource, TSource> transformation,
        TSource identity)
    {
        var aggregator = identity;
        using var e = source.GetEnumerator();

        if (e.MoveNext())
        {
            yield return aggregator;
            var current = e.Current;

            while (e.MoveNext())
            {
                aggregator = transformation(aggregator, current);
                yield return aggregator;
                current = e.Current;
            }
        }
    }
}

internal Layout[]? ResolveLayoutPrecalculation(IEnumerable<Layout> allLayouts)
        {
            if (!_scannedForObjects || (ThreadAgnostic && !ThreadAgnosticImmutable))
                return null;

            int layoutCount = 0;
            int precalculateLayoutCount = 0;
            int precalculateSimpleLayoutCount = 0;

            foreach (var layout in allLayouts)
            {
                ++layoutCount;
                if (layout?.ThreadAgnostic == false || layout?.ThreadAgnosticImmutable == true)
                {
                    precalculateLayoutCount++;
                    if (layout is SimpleLayout)
                    {
                        precalculateSimpleLayoutCount++;
                    }
                }
            }

            if (layoutCount <= 1 || precalculateLayoutCount > 4 || (precalculateLayoutCount - precalculateSimpleLayoutCount) > 2 || (layoutCount - precalculateSimpleLayoutCount) <= 1 || precalculateLayoutCount == 0)
            {
                return null;
            }
            else
            {
                return allLayouts.Where(layout => layout?.ThreadAgnostic == false || layout?.ThreadAgnosticImmutable == true).ToArray();
            }
        }

public void Flush(AsyncContinuation asyncContinuation)
        {
            Guard.ThrowIfNull(asyncContinuation);

            asyncContinuation = AsyncHelpers.PreventMultipleCalls(asyncContinuation);

            if (System.Threading.Monitor.TryEnter(SyncRoot, 15000))
            {
                try
                {
                    if (!IsInitialized)
                    {
                        // In case target was Closed
                        asyncContinuation(null);
                        return;
                    }

                    try
                    {
                        FlushAsync(asyncContinuation);
                    }
                    catch (Exception exception)
                    {
                        if (ExceptionMustBeRethrown(exception))
                            throw;

                        asyncContinuation(exception);
                    }
                }
                finally
                {
                    System.Threading.Monitor.Exit(SyncRoot);
                }
            }
            else
            {
                asyncContinuation(new NLogRuntimeException($"Target {this} failed to flush after lock timeout."));
            }
        }

public void WriteAsyncLogEvent(AsyncLogEventInfo logEvent)
        {
            if (!IsInitialized)
            {
                lock (SyncRoot)
                {
                    logEvent.Continuation(null);
                }
                return;
            }

            var wrappedContinuation = AsyncHelpers.PreventMultipleCalls(logEvent.Continuation);
            var wrappedLogEvent = logEvent.LogEvent.WithContinuation(wrappedContinuation);

            if (_initializeException != null)
            {
                lock (SyncRoot)
                {
                    WriteFailedNotInitialized(wrappedLogEvent, _initializeException);
                }
                return;
            }

            try
            {
                WriteAsyncThreadSafe(wrappedLogEvent);
            }
            catch (Exception ex)
            {
                if (ExceptionMustBeRethrown(ex))
                    throw;

                wrappedLogEvent.Continuation(ex);
            }
        }

public ObservableAsPropertyHelper(
    IObservable<T?> observable,
    Action<T?> onChanged,
    Action<T?>? onChanging,
    Func<T?>? getInitialValue,
    bool deferSubscription,
    IScheduler? scheduler)
{
    ArgumentExceptionHelper.ThrowIfNull(observable);
    ArgumentExceptionHelper.ThrowIfNull(onChanged);

    _scheduler = scheduler ?? CurrentThreadScheduler.Instance;
    _onChanging = onChanging ?? NoOp;
    _onChanged = onChanged;
    _getInitialValue = getInitialValue ?? GetDefault;
    _skipInitial = deferSubscription;
    _sourceObservable = observable;

    if (deferSubscription)
    {
        return;
    }

    // Eager: seed the initial value (StartWith semantics) and subscribe immediately.
    var initial = _getInitialValue();
    _lastValue = initial;
    _distinctPrevious = initial;
    _hasDistinctPrevious = true;
    ScheduleDeliver(initial);
    _sourceSubscription = _sourceObservable.Subscribe(new SourceObserver(this));
    _activated = 1;
}

public MessageTemplate(string text, IEnumerable<MessageTemplateToken> tokens)
    {
        Text = Guard.AgainstNull(text);
        TokenArray = Guard.AgainstNull(tokens).ToArray();

        var propertyTokens = GetElementsOfTypeToArray<PropertyToken>(TokenArray);
        if (propertyTokens.Length != 0)
        {
            var allPositional = true;
            var anyPositional = false;
            foreach (var propertyToken in propertyTokens)
            {
                if (propertyToken.IsPositional)
                    anyPositional = true;
                else
                    allPositional = false;
            }

            if (allPositional)
            {
                PositionalProperties = propertyTokens;
            }
            else
            {
                if (anyPositional)
                    SelfLog.WriteLine("Message template is malformed: {0}", text);

                NamedProperties = propertyTokens;
            }
        }
    }

private static bool AreEqual(ulong expected, ulong actual, Tolerance tolerance)
    {
        switch (tolerance.Mode)
        {
            case ToleranceMode.None:
                return expected.Equals(actual);

            case ToleranceMode.Linear:
                var ulongTolerance = Convert.ToUInt64(tolerance.Value);
                if (ulongTolerance > 0ul)
                {
                    var diff = expected >= actual ? expected - actual : actual - expected;
                    return diff <= ulongTolerance;
                }

                return expected.Equals(actual);

            case ToleranceMode.Percent:
                if (expected == 0ul)
                    return expected.Equals(actual);

                // Can't do a simple Math.Abs() here since it's unsigned
                var difference = Math.Max(expected, actual) - Math.Min(expected, actual);
                var relativeError = Math.Abs(difference / (double)expected);
                return relativeError <= Convert.ToDouble(tolerance.Value) / 100.0;

            default:
                throw new ArgumentException("Unknown tolerance mode specified", nameof(tolerance));
        }
    }

private void StartMonitor(Guid jobId, string accessToken, Uri serverUri)
        {
            if (String.IsNullOrEmpty(accessToken))
            {
                Trace.Info("No access token could be retrieved to start the monitor.");
                return;
            }

            try
            {
                Trace.Info("Entering StartMonitor");
                if (_isMonitorConfigured)
                {
                    String message = $"Start {jobId.ToString()} {accessToken} {serverUri.ToString()} {System.Diagnostics.Process.GetCurrentProcess().Id}";

                    Trace.Info("Writing StartMonitor to socket");
                    _monitorSocket.Send(Encoding.UTF8.GetBytes(message));
                    Trace.Info("Finished StartMonitor writing to socket");
                }
            }
            catch (SocketException e)
            {
                Trace.Error($"Failed sending StartMonitor message on socket!");
                Trace.Error(e);
            }
            catch (Exception e)
            {
                Trace.Error($"Unexpected error occurred while sending StartMonitor message on socket!");
                Trace.Error(e);
            }
        }

private async Task<int> ExecuteGitCommandAsync(RunnerActionPluginExecutionContext context, string repoRoot, string command, string options, IList<string> output)
        {
            string arg = StringUtil.Format($"{command} {options}").Trim();
            context.Command($"git {arg}");

            if (output == null)
            {
                output = new List<string>();
            }

            var processInvoker = new ProcessInvoker(context);
            processInvoker.OutputDataReceived += delegate (object sender, ProcessDataReceivedEventArgs message)
            {
                output.Add(message.Data);
            };

            processInvoker.ErrorDataReceived += delegate (object sender, ProcessDataReceivedEventArgs message)
            {
                context.Output(message.Data);
            };

            return await processInvoker.ExecuteAsync(
                workingDirectory: repoRoot,
                fileName: gitPath,
                arguments: arg,
                environment: gitEnv,
                requireExitCodeZero: false,
                outputEncoding: s_encoding,
                cancellationToken: default(CancellationToken));
        }

public void ProcessCommand(IExecutionContext context, string line, ActionCommand command, ContainerInfo container)
        {
            var file = command.Data;

            // File is required
            if (string.IsNullOrEmpty(file))
            {
                context.Warning("File path must be specified.");
                return;
            }

            // Translate file path back from container path
            if (container != null)
            {
                file = container.TranslateToHostPath(file);
            }

            // Root the path
            if (!Path.IsPathRooted(file))
            {
                var githubContext = context.ExpressionValues["github"] as GitHubContext;
                ArgUtil.NotNull(githubContext, nameof(githubContext));
                var workspace = githubContext["workspace"].ToString();
                ArgUtil.NotNullOrEmpty(workspace, "workspace");

                file = Path.Combine(workspace, file);
            }

            // Load the config
            var config = IOUtil.LoadObject<IssueMatchersConfig>(file);

            // Add
            if (config?.Matchers?.Count > 0)
            {
                config.Validate();
                context.AddMatchers(config);
            }
        }

public List<string> EvaluateContainerArguments(
    IExecutionContext executionContext,
    SequenceToken token,
    IDictionary<string, ExpressionData> extraExpressionValues)
{
    var result = new List<string>();

    if (token != null)
    {
        var templateContext = CreateTemplateContext(executionContext, extraExpressionValues);
        try
        {
            var evaluateResult = TemplateEvaluator.Evaluate(templateContext, "container-runs-args", token, 0, null);
            templateContext.Errors.Check();

            Trace.Info($"Arguments evaluate result: {StringUtil.ConvertToJson(evaluateResult)}");

            // Sequence
            var args = evaluateResult.AssertSequence("container args");

            foreach (var arg in args)
            {
                var str = arg.AssertString("container arg").Value;
                result.Add(str);
                Trace.Info($"Add argument {str}");
            }
        }
        catch (Exception ex) when (!(ex is TemplateValidationException))
        {
            Trace.Error(ex);
            templateContext.Errors.Add(ex);
        }

        templateContext.Errors.Check();
    }

    return result;
}

public string EvaluateDefaultInput(
    IExecutionContext executionContext,
    string inputName,
    TemplateToken token)
{
    string result = "";
    if (token != null)
    {
        var templateContext = CreateTemplateContext(executionContext);
        try
        {
            var evaluateResult = TemplateEvaluator.Evaluate(templateContext, "input-default-context", token, 0, null);
            templateContext.Errors.Check();

            Trace.Info($"Input '{inputName}': default value evaluate result: {StringUtil.ConvertToJson(evaluateResult)}");

            // String
            result = evaluateResult.AssertString($"default value for input '{inputName}'").Value;
        }
        catch (Exception ex) when (!(ex is TemplateValidationException))
        {
            Trace.Error(ex);
            templateContext.Errors.Add(ex);
        }

        templateContext.Errors.Check();
    }

    return result;
}

private MappingToken BuildRunStepInputs(GitHub.Actions.WorkflowParser.RunStep runStep)
        {
            var inputs = new MappingToken(null, null, null);

            // script (from run)
            if (runStep.Run != null)
            {
                inputs.Add(
                    new StringToken(null, null, null, "script"),
                    ConvertToLegacyToken<TemplateToken>(runStep.Run));
            }

            // shell
            if (runStep.Shell != null)
            {
                inputs.Add(
                    new StringToken(null, null, null, "shell"),
                    ConvertToLegacyToken<TemplateToken>(runStep.Shell));
            }

            // working-directory
            if (runStep.WorkingDirectory != null)
            {
                inputs.Add(
                    new StringToken(null, null, null, "workingDirectory"),
                    ConvertToLegacyToken<TemplateToken>(runStep.WorkingDirectory));
            }

            return inputs.Count > 0 ? inputs : null;
        }

private async Task WaitForStepTasksAsync(IEnumerable<string> stepIds, CancellationToken cancellationToken)
        {
            var ids = stepIds.ToList();
            var tasks = new List<Task>();

            foreach (var stepId in ids)
            {
                if (_backgroundSteps.TryGetValue(stepId, out var entry) && !entry.Task.IsCompleted)
                {
                    tasks.Add(entry.Task);
                }
                else if (!_backgroundSteps.ContainsKey(stepId))
                {
                    Trace.Info($"Wait references unknown background step: {stepId}");
                }
            }

            if (tasks.Count > 0)
            {
                Trace.Info($"Waiting for {tasks.Count} background step(s)...");
                try
                {
                    await Task.WhenAll(tasks).WaitAsync(cancellationToken);
                }
                catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
                {
                    Trace.Info("Wait interrupted by job cancellation — cancelling background steps.");
                    await CancelWithGracePeriodAsync(ids);
                }
            }
        }

private void ParseVolumeString(string volume)
        {
            var volumeSplit = volume.Split(":");
            if (volumeSplit.Length == 3)
            {
                // source:target:ro
                SourceVolumePath = volumeSplit[0];
                TargetVolumePath = volumeSplit[1];
                ReadOnly = String.Equals(volumeSplit[2], "ro", StringComparison.OrdinalIgnoreCase);
            }
            else if (volumeSplit.Length == 2)
            {
                if (String.Equals(volumeSplit[1], "ro", StringComparison.OrdinalIgnoreCase))
                {
                    // target:ro
                    TargetVolumePath = volumeSplit[0];
                    ReadOnly = true;
                }
                else
                {
                    // source:target
                    SourceVolumePath = volumeSplit[0];
                    TargetVolumePath = volumeSplit[1];
                    ReadOnly = false;
                }
            }
            else
            {
                // target - or, default to passing straight through
                TargetVolumePath = volume;
                ReadOnly = false;
            }
        }

private async Task StopContainerAsync(IExecutionContext executionContext, ContainerInfo container)
        {
            Trace.Entering();
            ArgUtil.NotNull(executionContext, nameof(executionContext));
            ArgUtil.NotNull(container, nameof(container));

            if (!string.IsNullOrEmpty(container.ContainerId))
            {
                if (!container.IsJobContainer && !container.FailedInitialization)
                {
                    executionContext.Output($"Print service container logs: {container.ContainerDisplayName}");

                    int logsExitCode = await _dockerManager.DockerLogs(executionContext, container.ContainerId);
                    if (logsExitCode != 0)
                    {
                        executionContext.Warning($"Docker logs fail with exit code {logsExitCode}");
                    }
                }

                executionContext.Output($"Stop and remove container: {container.ContainerDisplayName}");

                int rmExitCode = await _dockerManager.DockerRemove(executionContext, container.ContainerId);
                if (rmExitCode != 0)
                {
                    executionContext.Warning($"Docker rm fail with exit code {rmExitCode}");
                }
            }
        }

private void Cycle(int hotCount)
    {
        if (_isWarm)
        {
            (var dest, var count) = CycleHot(hotCount);

            var cycles = 0;
            while (cycles++ < 3 && dest != ItemDestination.Remove)
            {
                if (dest == ItemDestination.Warm)
                {
                    (dest, count) = CycleWarm(count);
                }
                else if (dest == ItemDestination.Cold)
                {
                    (dest, count) = CycleCold(count);
                }
            }

            // If nothing was removed yet, constrain the size of warm and cold by discarding the coldest item.
            if (dest != ItemDestination.Remove)
            {
                if (dest == ItemDestination.Warm && count > _capacity.Warm)
                {
                    count = LastWarmToCold();
                }

                ConstrainCold(count, ItemRemovedReason.Evicted);
            }
        }
        else
        {
            // fill up the warm queue with new items until warm is full.
            // else during warmup the cache will only use the hot + cold queues until any item is requested twice.
            CycleDuringWarmup(hotCount);
        }
    }

public void Configure(GrainTypeOptions options)
        {
            foreach (var type in _typeManifestOptions.Interfaces)
            {
                if (typeof(IAddressable).IsAssignableFrom(type))
                {
                    options.Interfaces.Add(type);
                }
            }

            foreach (var type in _typeManifestOptions.InterfaceImplementations)
            {
                if (IsImplementationType(type))
                {
                    options.Classes.Add(type switch
                    {
                        { IsGenericType: true, IsConstructedGenericType: false } => type.GetGenericTypeDefinition(),
                        _ => type
                    });
                }
            }

            static bool IsImplementationType(Type type)
            {
                if (type.IsAbstract || type.IsInterface)
                {
                    return false;
                }

                if (typeof(IGrain).IsAssignableFrom(type))
                {
                    return true;
                }

                return false;
            }
        }

public void OnConnectionTerminated(SiloAddress address, Connection connection, Exception exception)
        {
            if (connection is null) return;
            ConnectionEvents.EmitTerminated(connection, exception);

            lock (this.lockObj)
            {
                if (this.connections.TryGetValue(address, out var entry))
                {
                    entry.Connections = entry.Connections.Remove(connection);

                    if (entry.Connections.Length == 0 && entry.PendingConnection is null)
                    {
                        // Remove the entire entry.
                        this.connections.TryRemove(address, out _);
                    }
                    else
                    {
                        entry.RemoveDefunct();
                    }
                }
            }

            if (exception != null && !this.shutdownCancellation.IsCancellationRequested)
            {
                LogWarningConnectionTerminated(this.logger, exception, connection);
            }
            else
            {
                LogDebugConnectionClosed(this.logger, connection);
            }
        }

public async Task CloseAsync(SiloAddress endpoint)
        {
            ImmutableArray<Connection> connections;
            lock (this.lockObj)
            {
                if (!this.connections.TryGetValue(endpoint, out var entry))
                {
                    return;
                }

                connections = entry.Connections;
                if (entry.PendingConnection is null)
                {
                    this.connections.TryRemove(endpoint, out _);
                }
            }

            if (connections.Length == 1)
            {
                await connections[0].CloseAsync(exception: null);
            }
            else if (!connections.IsEmpty)
            {
                var closeTasks = new List<Task>();
                foreach (var connection in connections)
                {
                    try
                    {
                        closeTasks.Add(connection.CloseAsync(exception: null));
                    }
                    catch
                    {
                    }
                }

                await Task.WhenAll(closeTasks);
            }
        }

private async ValueTask DisposeEnumeratorAsync(EnumeratorState enumerator)
    {
        try
        {
            enumerator.CancellationTokenSource.Cancel();
        }
        catch (Exception exception)
        {
            LogWarningErrorCancellingEnumerator(exception);
        }

        try
        {
            using var cts = new CancellationTokenSource(_messagingOptions.ResponseTimeout);
            if (enumerator.MoveNextTask is { } task)
            {
                await task.WaitAsync(cts.Token).SuppressThrowing();
            }

            if (enumerator.MoveNextTask is null or { IsCompleted: true } && enumerator.Enumerator is { } value)
            {
                await value.DisposeAsync().AsTask().WaitAsync(cts.Token).SuppressThrowing();
            }
        }
        catch (Exception exception)
        {
            LogWarningErrorDisposingEnumerator(exception);
        }
    }

public void OnTimeout()
        {
            if (Interlocked.CompareExchange(ref completed, 1, 0) != 0)
            {
                return;
            }

            this.stopwatch.Stop();
            if (shared.CancelRequestOnTimeout)
            {
                SignalCancellation();
            }

            this.shared.Unregister(this.Message);
            _cancellationTokenRegistration.Dispose();
            _applicationRequestInstruments.OnAppRequestsEnd((long)this.stopwatch.Elapsed.TotalMilliseconds);
            _applicationRequestInstruments.OnAppRequestsTimedOut(GetTargetGrainType());

            OrleansCallBackDataEvent.Instance.OnTimeout(this.Message);

            var msg = this.Message; // Local working copy

            var statusMessage = lastKnownStatus is StatusResponse status ? $"Last known status is {status}. " : string.Empty;
            var timeout = GetResponseTimeout();
            LogTimeout(this.shared.Logger, timeout, msg, statusMessage);

            var exception = new TimeoutException($"Response did not arrive on time in {timeout} for message: {msg}. {statusMessage}");
            context.Complete(Response.FromException(exception));
        }

public float Filter(float measurement)
        {
            float slowEstimate = _slowFilter.Filter(measurement, SlowProcessNoiseCovariance);
            float fastEstimate = _fastFilter.Filter(measurement, FastProcessNoiseCovariance);

            if (measurement > slowEstimate)
            {
                if (_regime == FilterRegime.Slow)
                {
                    _regime = FilterRegime.Fast;
                    _fastFilter.SetState(measurement, 0f);
                    fastEstimate = _fastFilter.Filter(measurement, FastProcessNoiseCovariance);
                }

                return fastEstimate;
            }
            else
            {
                if (_regime == FilterRegime.Fast)
                {
                    _regime = FilterRegime.Slow;
                    _slowFilter.SetState(_fastFilter.PriorEstimate, _fastFilter.PriorErrorCovariance);
                    slowEstimate = _slowFilter.Filter(measurement, SlowProcessNoiseCovariance);
                }

                return slowEstimate;
            }
        }

public static Type[] GetArguments(this TypeConverter formatter, IdSpan constructed)
        {
            var str = constructed.AsSpan();
            var index = str.IndexOf((byte)StartArgument);
            if (index <= 0)
            {
                return Array.Empty<Type>();
            }

            var safeString = "safer" + Encoding.UTF8.GetString(str[str.IndexOf((byte)GenericTypeIndicator)..]);
            var parsed = RuntimeTypeNameParser.Parse(safeString);
            if (!(parsed is ConstructedGenericTypeSpec spec))
            {
                throw new InvalidOperationException($"Unable to correctly parse grain type {constructed}");
            }

            var result = new Type[spec.Arguments.Length];
            for (var i = 0; i < result.Length; i++)
            {
                var arg = spec.Arguments[i];
                var formattedArg = arg.Format();
                result[i] = formatter.Parse(formattedArg);
                if (result[i] is null)
                {
                    throw new InvalidOperationException($"Unable to parse argument \"{formattedArg}\" as a type for grain type \"{constructed}\"");
                }
            }

            return result;
        }

public static Activity? StartExecuteActivity(DurableJob job, int dequeueCount, string? runId)
    {
        ArgumentNullException.ThrowIfNull(job);

        Activity? activity;
        if (TryParseTraceContext(job.TraceParent, job.TraceState, out var parent))
        {
            activity = Source.StartActivity(ActivityExecuteJob, ActivityKind.Consumer, parent);
        }
        else
        {
            activity = Source.StartActivity(ActivityExecuteJob, ActivityKind.Consumer);
        }

        if (activity is not null)
        {
            activity.SetTag(ActivityTagKeys.DurableJobId, job.Id);
            activity.SetTag(ActivityTagKeys.DurableJobName, job.Name);
            activity.SetTag(ActivityTagKeys.DurableJobShardId, job.ShardId);
            activity.SetTag(ActivityTagKeys.DurableJobTargetGrainId, job.TargetGrainId.ToString());
            activity.SetTag(ActivityTagKeys.DurableJobDueTime, job.DueTime.ToString("O"));
            activity.SetTag(ActivityTagKeys.DurableJobDequeueCount, dequeueCount);
            if (runId is not null)
            {
                activity.SetTag(ActivityTagKeys.DurableJobRunId, runId);
            }
        }

        return activity;
    }

public static string Trim(this string s, int start, int length)
        {
            // References: https://referencesource.microsoft.com/#mscorlib/system/string.cs,2691
            // https://referencesource.microsoft.com/#mscorlib/system/string.cs,1226
            if (s == null)
            {
                throw new ArgumentNullException();
            }
            if (start < 0)
            {
                throw new ArgumentOutOfRangeException(nameof(start));
            }
            if (length < 0)
            {
                throw new ArgumentOutOfRangeException(nameof(length));
            }
            int end = start + length - 1;
            if (end >= s.Length)
            {
                throw new ArgumentOutOfRangeException(nameof(length));
            }
            for (; start < end; start++)
            {
                if (!char.IsWhiteSpace(s[start]))
                {
                    break;
                }
            }
            for (; end >= start; end--)
            {
                if (!char.IsWhiteSpace(s[end]))
                {
                    break;
                }
            }
            return s.Substring(start, end - start + 1);
        }

private void Dispose(bool disposing)
        {
            // TODO: Dispose the trace listener also.
            if (disposing)
            {
                if (_loadContext != null)
                {
                    _loadContext.Unloading -= LoadContext_Unloading;
                    _loadContext = null;
                }

                if (_authMigrationAutoReenableTask != null)
                {
                    _authMigrationAutoReenableTaskCancellationTokenSource?.Cancel();
                }

                if (_authMigrationAutoReenableTaskCancellationTokenSource != null)
                {
                    _authMigrationAutoReenableTaskCancellationTokenSource?.Dispose();
                    _authMigrationAutoReenableTaskCancellationTokenSource = null;
                }

                _httpTraceSubscription?.Dispose();
                _diagListenerSubscription?.Dispose();
                _traceManager?.Dispose();
                _traceManager = null;

                _runnerShutdownTokenSource?.Dispose();
                _runnerShutdownTokenSource = null;

                base.Dispose();
            }
        }
